import {
  Sprout, ArrowRight, Lock, Check, Sparkles, ShieldCheck,
  Mail, Phone, User, CreditCard, PartyPopper, Calendar, ChevronLeft, MapPin, ShoppingCart, Play,
  LayoutGrid, Wallet, Repeat, Trash2, Leaf, ChevronRight, X, BookOpen, Plus,
} from "lucide-react";
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from "recharts";

const NATHALIA_PHOTO = "data:image/jpeg;base64,";

const NATHALIA_HERO_PHOTO = "data:image/jpeg;base64,";

const CATEGORY_SPLIT = [
  { name: "Moradia", pct: 0.35, color: "#5B7A63" },
  { name: "Mercado", pct: 0.15, color: "#C98A4B" },
  { name: "Transporte", pct: 0.12, color: "#6E8AA6" },
  { name: "Assinaturas", pct: 0.08, color: "#8B6BA8" },
  { name: "Lazer", pct: 0.10, color: "#B5657A" },
  { name: "Outros", pct: 0.20, color: "#9B8F73" },
];

const APP_OPTIONS = [
  "Netflix", "Spotify", "Amazon Prime", "Disney+", "HBO Max",
  "Academia", "iCloud / Google One", "Uber / iFood", "YouTube Premium", "Outro",
];

// Checklist interativo, desenhado como um planejador financeiro pensaria:
