// pela área de membros do Kiwify, com liberação semanal nativa de lá.
const VIDEO_LINKS = {
  hero: hXHOIxBUePM,
  pagamento: null,
};

const ALL_SCORED_ITEMS = [...ESSENCIAL_ITEMS, ...FLEXIVEL_ITEMS];

// ---------- Dashboard completo (o "app" de verdade, liberado após o pagamento) ----------
const DASH_CATEGORY_META = {
  Moradia: { color: "#5B7A63", icon: "🏠", seedPct: 0.32 },
  Mercado: { color: "#C98A4B", icon: "🛒", seedPct: 0.14 },
  Restaurantes: { color: "#D97F52", icon: "🍽️", seedPct: 0.08 },
  Transporte: { color: "#6E8AA6", icon: "🚗", seedPct: 0.11 },
  Assinaturas: { color: "#8B6BA8", icon: "📱", seedPct: 0.07 },
  Lazer: { color: "#B5657A", icon: "🎬", seedPct: 0.09 },
  Saúde: { color: "#4C8577", icon: "💊", seedPct: 0.07 },
  Outros: { color: "#9B8F73", icon: "📦", seedPct: 0.12 },
};
const DASH_CATEGORY_NAMES = Object.keys(DASH_CATEGORY_META);
const DASH_TABS = [
  { id: "visao", label: "Visão geral", icon: LayoutGrid },
  { id: "renda", label: "Renda & meta", icon: Wallet },
  { id: "gastos", label: "Gastos", icon: ShoppingCart },
  { id: "assinaturas", label: "Assinaturas", icon: Repeat },
  { id: "mentalidade", label: "Mentalidade", icon: Leaf },
];
const DASH_MINDSET_TIPS = [
  { title: "Você não sobe até suas metas. Você cai até seus sistemas.", body: "Um sistema automático — como separar uma parte da renda no dia do pagamento — funciona mesmo nas semanas difíceis, sem depender de força de vontade." },
  { title: "Acompanhe antes de julgar.", body: "Olhar pros próprios gastos não é sobre culpa, é sobre clareza. O objetivo é enxergar pra onde o dinheiro vai, não ser perfeito desde o primeiro mês." },
  { title: "Pague o seu 'eu do futuro' primeiro.", body: "Se poupança é o que sobra no fim do mês, geralmente sobra pouco. Separe o valor de guardar assim que a renda cai, e viva com o resto." },
  { title: "Dinheiro é mais emocional do que parece.", body: "A maioria das decisões financeiras não é racional — é sobre segurança, status ou alívio. Perceber a emoção por trás de um gasto é o primeiro passo pra mudar o padrão." },
];

function Dashboard({ initialRenda, initialGasto, initialApps, habitosParaRevisar, symbol, isBR }) {
  const [tab, setTab] = useState("visao");
  const [income, setIncome] = useState({ salario: initialRenda || 0, extra: 0 });
  const [savingsPct, setSavingsPct] = useState(20);
  const [budgets, setBudgets] = useState(() => {
    const b = {};
    DASH_CATEGORY_NAMES.forEach((c) => { b[c] = Math.round((initialGasto || 0) * DASH_CATEGORY_META[c].seedPct * 1.15); });
    return b;
  });
  const [expenses, setExpenses] = useState(() => {
    const seeded = DASH_CATEGORY_NAMES.filter((c) => c !== "Assinaturas").map((c, i) => ({
      id: i + 1, name: `Estimado do seu diagnóstico`, category: c,
      amount: Math.round((initialGasto || 0) * DASH_CATEGORY_META[c].seedPct), recurring: false,
    }));
    const apps = (initialApps || []).filter((a) => a !== "Outro").map((app, i) => ({
      id: 900 + i, name: app, category: "Assinaturas", amount: 12, recurring: true,
    }));
    return [...seeded, ...apps];
  });
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ name: "", category: "Mercado", amount: "", recurring: false });
  const [cardIndex, setCardIndex] = useState(0);

  const totalIncome = income.salario + income.extra;
  const totals = useMemo(() => {
    const byCategory = {};
    DASH_CATEGORY_NAMES.forEach((c) => (byCategory[c] = 0));
    expenses.forEach((e) => (byCategory[e.category] += e.amount));
    const totalSpent = Object.values(byCategory).reduce((a, b) => a + b, 0);
    const subscriptions = expenses.filter((e) => e.recurring);
    const subsTotal = subscriptions.reduce((a, e) => a + e.amount, 0);
    return { byCategory, totalSpent, subscriptions, subsTotal };
  }, [expenses]);

  const actualSavings = totalIncome - totals.totalSpent;
  const recommendedSavings = totalIncome * (savingsPct / 100);
  const savingsGap = actualSavings - recommendedSavings;
  const savingsRateReal = totalIncome > 0 ? (actualSavings / totalIncome) * 100 : 0;
  const overBudgetCats = DASH_CATEGORY_NAMES.filter((c) => totals.byCategory[c] > budgets[c]);
  const dashFmt = (n) => Math.round(n).toLocaleString(isBR ? "pt-BR" : "en-US");

  const cutSuggestions = useMemo(() => {
    const list = (habitosParaRevisar || []).map((h) => ({ label: `⚠ ${h}`, detail: "Você marcou esse hábito no seu diagnóstico inicial — é um bom ponto de partida." }));
    overBudgetCats.forEach((c) => {
      list.push({ label: `${DASH_CATEGORY_META[c].icon} ${c} estourou o orçamento`, detail: `Gasto de ${symbol} ${dashFmt(totals.byCategory[c])} contra um limite de ${symbol} ${dashFmt(budgets[c])}.` });
    });
    return list;
  }, [habitosParaRevisar, overBudgetCats, totals, budgets]);

  const pieData = DASH_CATEGORY_NAMES.map((c) => ({ name: c, value: totals.byCategory[c] })).filter((d) => d.value > 0);
  const barData = DASH_CATEGORY_NAMES.map((c) => ({ name: c.length > 8 ? c.slice(0, 7) + "…" : c, Orçado: budgets[c], Gasto: totals.byCategory[c] }));

  const addExpense = () => {
    if (!form.name.trim() || !form.amount) return;
    setExpenses((prev) => [...prev, { id: Date.now(), name: form.name.trim(), category: form.category, amount: parseFloat(form.amount), recurring: form.recurring }]);
    setForm({ name: "", category: "Mercado", amount: "", recurring: false });
    setShowForm(false);
  };
  const removeExpense = (id) => setExpenses((prev) => prev.filter((e) => e.id !== id));

  const card = (label, value, sub, color) => (
    <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: "14px 16px", flex: 1, minWidth: 0 }}>
      <div style={{ fontSize: 11, color: "#8B9A8E", fontWeight: 600, letterSpacing: 0.3, marginBottom: 4 }}>{label}</div>
      <div className="sprout-mono" style={{ fontSize: 19, fontWeight: 700, color: color || "#26332B", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
        {symbol} {dashFmt(value)}
      </div>
      {sub && <div style={{ fontSize: 10.5, color: "#8B9A8E", marginTop: 2 }}>{sub}</div>}
    </div>
  );

  return (
    <div style={{ fontFamily: "'Inter', -apple-system, sans-serif", background: "#F3F1E9", minHeight: "100%", color: "#26332B" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,600;9..144,700&family=Inter:wght@400;500;600;700&family=IBM+Plex+Mono:wght@500;600&display=swap');
        .sprout-serif { font-family: 'Fraunces', serif; }
        .sprout-mono { font-family: 'IBM Plex Mono', monospace; }
        .tab-btn { transition: all 0.15s ease; }
        .row-hover:hover { background: #F3EFE0 !important; }
        .fab:hover { transform: scale(1.06); }
        input[type=range] { accent-color: #5B7A63; }
      `}</style>
      <div style={{ maxWidth: 620, margin: "0 auto", padding: "24px 18px 100px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 18 }}>
          <div style={{ width: 38, height: 38, borderRadius: 10, background: "#5B7A63", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            <Sprout size={20} color="#F3F1E9" />
          </div>
          <div>
            <div className="sprout-serif" style={{ fontSize: 20, fontWeight: 600, lineHeight: 1 }}>Freedom Score</div>
            <div style={{ fontSize: 11, color: "#6B7A70", letterSpacing: 0.3 }}>sua liberdade financeira, semana a semana</div>
          </div>
        </div>

        <div style={{ display: "flex", gap: 6, marginBottom: 18, overflowX: "auto", paddingBottom: 2 }}>
          {DASH_TABS.map((t) => {
            const Icon = t.icon;
            const active = tab === t.id;
            return (
              <button key={t.id} className="tab-btn" onClick={() => setTab(t.id)}
                style={{ display: "flex", alignItems: "center", gap: 6, whiteSpace: "nowrap", padding: "8px 13px", borderRadius: 999, border: active ? "1px solid #5B7A63" : "1px solid #E4DECB", background: active ? "#5B7A63" : "#FBF9F3", color: active ? "#F3F1E9" : "#4B5A50", fontSize: 12.5, fontWeight: 600, cursor: "pointer", flexShrink: 0 }}>
                <Icon size={13} /> {t.label}
              </button>
            );
          })}
        </div>

        {tab === "visao" && (
          <>
            <div style={{ display: "flex", gap: 10, marginBottom: 12, flexWrap: "wrap" }}>
              {card("Renda mensal", totalIncome, null, "#26332B")}
              {card("Gastos do mês", totals.totalSpent, null, "#B14D61")}
            </div>
            <div style={{ display: "flex", gap: 10, marginBottom: 18, flexWrap: "wrap" }}>
              {card("Guardado este mês", actualSavings, `meta: ${symbol} ${dashFmt(recommendedSavings)}`, actualSavings >= recommendedSavings ? "#5B7A63" : "#B14D61")}
              {card("Taxa de poupança", savingsRateReal, `meta: ${savingsPct}% da renda`, "#26332B")}
            </div>

            <div style={{ background: "#26332B", borderRadius: 18, padding: 18, marginBottom: 18 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                <span style={{ color: "#B9C4B4", fontSize: 12, fontWeight: 600 }}>PROGRESSO DA META DE POUPANÇA</span>
                <span className="sprout-mono" style={{ color: "#F3F1E9", fontSize: 13 }}>{recommendedSavings > 0 ? Math.min(100, Math.round((actualSavings / recommendedSavings) * 100)) : 0}%</span>
              </div>
              <div style={{ height: 10, background: "#1D2721", borderRadius: 6, overflow: "hidden" }}>
                <div style={{ height: "100%", width: `${Math.max(0, Math.min(100, (actualSavings / (recommendedSavings || 1)) * 100))}%`, background: "linear-gradient(90deg, #8FB396, #5B7A63)", transition: "width 0.5s ease" }} />
              </div>
              <div style={{ color: savingsGap >= 0 ? "#8FB396" : "#E8A2AE", fontSize: 12, marginTop: 8 }}>
                {savingsGap >= 0 ? `Você está ${symbol} ${dashFmt(savingsGap)} acima da meta. 🌱` : `Faltam ${symbol} ${dashFmt(Math.abs(savingsGap))} pra bater a meta do mês.`}
              </div>
            </div>

            <div className="sprout-serif" style={{ fontSize: 16, fontWeight: 600, marginBottom: 10 }}>Gastos por categoria</div>
            <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: "12px 8px", marginBottom: 18 }}>
              <ResponsiveContainer width="100%" height={220}>
                <PieChart>
                  <Pie data={pieData} dataKey="value" nameKey="name" innerRadius={55} outerRadius={85} paddingAngle={2}>
                    {pieData.map((d) => <Cell key={d.name} fill={DASH_CATEGORY_META[d.name].color} />)}
                  </Pie>
                  <Tooltip formatter={(v) => `${symbol} ${dashFmt(v)}`} contentStyle={{ fontFamily: "Inter", fontSize: 12, borderRadius: 8 }} />
                </PieChart>
              </ResponsiveContainer>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "6px 14px", justifyContent: "center", marginTop: 4 }}>
                {pieData.map((d) => (
                  <div key={d.name} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11.5, color: "#4B5A50" }}>
                    <div style={{ width: 8, height: 8, borderRadius: "50%", background: DASH_CATEGORY_META[d.name].color }} />
                    {d.name}
                  </div>
                ))}
              </div>
            </div>

            {cutSuggestions.length > 0 && (
              <>
                <div className="sprout-serif" style={{ fontSize: 16, fontWeight: 600, marginBottom: 10 }}>O que dá pra cortar</div>
                <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 8 }}>
                  {cutSuggestions.map((s, i) => (
                    <div key={i} style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 12, padding: "12px 14px" }}>
                      <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 3 }}>{s.label}</div>
                      <div style={{ fontSize: 12, color: "#5C6B5F", lineHeight: 1.4 }}>{s.detail}</div>
                    </div>
                  ))}
                </div>
              </>
            )}
          </>
        )}

        {tab === "renda" && (
          <>
            <div className="sprout-serif" style={{ fontSize: 16, fontWeight: 600, marginBottom: 10 }}>Sua renda mensal</div>
            <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: 18, marginBottom: 18 }}>
              <label style={{ fontSize: 12, fontWeight: 600, color: "#4B5A50" }}>Salário / renda fixa</label>
              <input type="number" value={income.salario} onChange={(e) => setIncome({ ...income, salario: parseFloat(e.target.value) || 0 })}
                style={{ width: "100%", border: "1px solid #D8D2BC", borderRadius: 10, padding: "10px 12px", fontSize: 14, margin: "6px 0 14px", background: "#FFFFFF", boxSizing: "border-box" }} />
              <label style={{ fontSize: 12, fontWeight: 600, color: "#4B5A50" }}>Renda extra</label>
              <input type="number" value={income.extra} onChange={(e) => setIncome({ ...income, extra: parseFloat(e.target.value) || 0 })}
                style={{ width: "100%", border: "1px solid #D8D2BC", borderRadius: 10, padding: "10px 12px", fontSize: 14, margin: "6px 0 4px", background: "#FFFFFF", boxSizing: "border-box" }} />
            </div>

            <div className="sprout-serif" style={{ fontSize: 16, fontWeight: 600, marginBottom: 10 }}>Quanto guardar por mês</div>
            <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: 18, marginBottom: 18 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
                <span style={{ fontSize: 12.5, color: "#4B5A50" }}>Percentual da renda</span>
                <span className="sprout-mono" style={{ fontSize: 13, fontWeight: 700 }}>{savingsPct}%</span>
              </div>
              <input type="range" min="5" max="40" value={savingsPct} onChange={(e) => setSavingsPct(parseInt(e.target.value))} style={{ width: "100%", marginBottom: 12 }} />
              <div style={{ background: "#26332B", borderRadius: 12, padding: 14, textAlign: "center" }}>
                <div style={{ color: "#B9C4B4", fontSize: 11 }}>VALOR RECOMENDADO A GUARDAR / MÊS</div>
                <div className="sprout-mono" style={{ color: "#8FB396", fontSize: 24, fontWeight: 700 }}>{symbol} {dashFmt(recommendedSavings)}</div>
              </div>
            </div>
          </>
        )}

        {tab === "gastos" && (
          <>
            <div className="sprout-serif" style={{ fontSize: 16, fontWeight: 600, marginBottom: 10 }}>Orçado vs. gasto real</div>
            <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: "14px 8px", marginBottom: 18 }}>
              <ResponsiveContainer width="100%" height={200}>
                <BarChart data={barData} margin={{ top: 4, right: 8, left: -20, bottom: 0 }}>
                  <XAxis dataKey="name" tick={{ fontSize: 10, fill: "#6B7A70" }} axisLine={{ stroke: "#E4DECB" }} tickLine={false} />
                  <YAxis tick={{ fontSize: 10, fill: "#6B7A70" }} axisLine={false} tickLine={false} />
                  <Tooltip formatter={(v) => `${symbol} ${dashFmt(v)}`} contentStyle={{ fontFamily: "Inter", fontSize: 12, borderRadius: 8 }} />
                  <Bar dataKey="Orçado" fill="#D8D2BC" radius={[4, 4, 0, 0]} />
                  <Bar dataKey="Gasto" fill="#5B7A63" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div className="sprout-serif" style={{ fontSize: 16, fontWeight: 600, marginBottom: 10 }}>Todos os gastos</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 20 }}>
              {expenses.slice().reverse().map((e) => (
                <div key={e.id} className="row-hover" style={{ display: "flex", justifyContent: "space-between", alignItems: "center", background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 12, padding: "10px 12px" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 10, minWidth: 0 }}>
                    <span style={{ fontSize: 16 }}>{DASH_CATEGORY_META[e.category].icon}</span>
                    <div style={{ minWidth: 0 }}>
                      <div style={{ fontSize: 13.5, fontWeight: 600, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{e.name}</div>
                      <div style={{ fontSize: 11, color: "#8B9A8E" }}>{e.category}{e.recurring ? " · recorrente" : ""}</div>
                    </div>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 10, flexShrink: 0 }}>
                    <span className="sprout-mono" style={{ fontSize: 13.5, fontWeight: 600 }}>{symbol} {dashFmt(e.amount)}</span>
                    <button onClick={() => removeExpense(e.id)} style={{ background: "none", border: "none", cursor: "pointer", padding: 2 }}>
                      <Trash2 size={14} color="#C4677A" />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}

        {tab === "assinaturas" && (
          <>
            <div style={{ background: "#26332B", borderRadius: 18, padding: 18, marginBottom: 18 }}>
              <div style={{ color: "#B9C4B4", fontSize: 12, marginBottom: 4 }}>TOTAL EM ASSINATURAS / RECORRÊNCIAS</div>
              <div className="sprout-mono" style={{ color: "#F3F1E9", fontSize: 26, fontWeight: 700 }}>{symbol} {dashFmt(totals.subsTotal)}<span style={{ fontSize: 13, color: "#8B9A8E" }}> /mês</span></div>
              <div style={{ color: "#8FB396", fontSize: 12, marginTop: 6 }}>{symbol} {dashFmt(totals.subsTotal * 12)} por ano</div>
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 6, marginBottom: 20 }}>
              {totals.subscriptions.map((e) => (
                <div key={e.id} className="row-hover" style={{ display: "flex", justifyContent: "space-between", alignItems: "center", background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 12, padding: "10px 12px" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <Repeat size={14} color="#8B6BA8" />
                    <span style={{ fontSize: 13.5, fontWeight: 600 }}>{e.name}</span>
                  </div>
                  <span className="sprout-mono" style={{ fontSize: 13.5, fontWeight: 600 }}>{symbol} {dashFmt(e.amount)}/mês</span>
                </div>
              ))}
            </div>
          </>
        )}

        {tab === "mentalidade" && (
          <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 18, padding: 20 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 10 }}>
              <Leaf size={14} color="#5B7A63" />
              <span style={{ fontSize: 11, fontWeight: 700, color: "#5B7A63", letterSpacing: 0.6 }}>MENTALIDADE</span>
            </div>
            <div className="sprout-serif" style={{ fontSize: 18, fontWeight: 600, lineHeight: 1.3, marginBottom: 8 }}>{DASH_MINDSET_TIPS[cardIndex].title}</div>
            <div style={{ fontSize: 13.5, color: "#4B5A50", lineHeight: 1.55, marginBottom: 14 }}>{DASH_MINDSET_TIPS[cardIndex].body}</div>
            <button onClick={() => setCardIndex((i) => (i + 1) % DASH_MINDSET_TIPS.length)}
              style={{ background: "transparent", border: "none", color: "#5B7A63", fontSize: 13, fontWeight: 600, cursor: "pointer", display: "flex", alignItems: "center", gap: 4, padding: 0 }}>
              Próxima dica <ChevronRight size={14} />
            </button>
          </div>
        )}

        {tab === "mentalidade" && (
          <div style={{ marginTop: 20 }}>
            <div className="sprout-serif" style={{ fontSize: 16, fontWeight: 600, marginBottom: 4 }}>Série com a Nathália</div>
            <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: 18, display: "flex", gap: 12, alignItems: "flex-start" }}>
              <div style={{ fontSize: 20 }}>📩</div>
              <div>
                <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 4 }}>3 vídeos, um por semana</div>
                <div style={{ fontSize: 12.5, color: "#5C6B5F", lineHeight: 1.5 }}>
                  Você vai receber acesso por e-mail — um vídeo novo é liberado a cada 7 dias, contando a partir da sua compra.
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {(tab === "gastos" || tab === "visao") && (
        <button className="fab" onClick={() => setShowForm(true)}
          style={{ position: "fixed", bottom: 24, right: "50%", transform: "translateX(270px)", width: 52, height: 52, borderRadius: "50%", background: "#5B7A63", border: "none", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 8px 20px rgba(91,122,99,0.4)", cursor: "pointer" }}>
          <Plus size={24} color="#F3F1E9" />
        </button>
      )}

      {showForm && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(38,51,43,0.45)", display: "flex", alignItems: "flex-end", justifyContent: "center", zIndex: 50 }} onClick={() => setShowForm(false)}>
          <div onClick={(e) => e.stopPropagation()} style={{ background: "#F3F1E9", width: "100%", maxWidth: 480, borderRadius: "22px 22px 0 0", padding: 24 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <div className="sprout-serif" style={{ fontSize: 18, fontWeight: 600 }}>Registrar gasto</div>
              <button onClick={() => setShowForm(false)} style={{ background: "none", border: "none", cursor: "pointer" }}><X size={20} color="#6B7A70" /></button>
            </div>
            <label style={{ fontSize: 12, fontWeight: 600, color: "#4B5A50" }}>Foi gasto com o quê?</label>
            <input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="ex: Supermercado"
              style={{ width: "100%", border: "1px solid #D8D2BC", borderRadius: 10, padding: "10px 12px", fontSize: 14, margin: "6px 0 14px", background: "#FBF9F3", boxSizing: "border-box" }} />
            <label style={{ fontSize: 12, fontWeight: 600, color: "#4B5A50" }}>Categoria</label>
            <select value={form.category} onChange={(e) => setForm({ ...form, category: e.target.value })}
              style={{ width: "100%", border: "1px solid #D8D2BC", borderRadius: 10, padding: "10px 12px", fontSize: 14, margin: "6px 0 14px", background: "#FBF9F3", boxSizing: "border-box" }}>
              {DASH_CATEGORY_NAMES.map((c) => <option key={c} value={c}>{c}</option>)}
            </select>
            <label style={{ fontSize: 12, fontWeight: 600, color: "#4B5A50" }}>Valor</label>
            <input value={form.amount} onChange={(e) => setForm({ ...form, amount: e.target.value })} placeholder="0,00" type="number"
              style={{ width: "100%", border: "1px solid #D8D2BC", borderRadius: 10, padding: "10px 12px", fontSize: 14, margin: "6px 0 14px", background: "#FBF9F3", boxSizing: "border-box" }} />
            <label style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 13, color: "#4B5A50", marginBottom: 18, cursor: "pointer" }}>
              <input type="checkbox" checked={form.recurring} onChange={(e) => setForm({ ...form, recurring: e.target.checked })} />
              É uma assinatura / gasto recorrente
            </label>
            <button onClick={addExpense} style={{ width: "100%", background: "#5B7A63", color: "#F3F1E9", border: "none", borderRadius: 12, padding: "13px", fontSize: 14, fontWeight: 700, cursor: "pointer" }}>
              Salvar gasto
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// "regiao" vem antes de tudo: define moeda pro resto da jornada.
const STEP_ORDER = ["regiao", "hero", "cadastro", "financas", "detalhes", "prioridades", "parcial", "pagamento", "completo", "app"];
const GATED = ["cadastro", "financas", "detalhes", "prioridades", "parcial", "pagamento"];

const WRAP_STYLE = { fontFamily: "'Inter', -apple-system, sans-serif", background: "#F3F1E9", minHeight: "100%", color: "#26332B" };

function VideoCard({ caption, videoId, locked, lockLabel }) {
  if (locked) {
    return (
      <div style={{ position: "relative", borderRadius: 16, overflow: "hidden", aspectRatio: "16/9", background: "#E4DECB", marginBottom: 16, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 8 }}>
        <div style={{ width: 44, height: 44, borderRadius: "50%", background: "#C9C4B0", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <Lock size={18} color="#5C6B5F" />
        </div>
        <div style={{ fontSize: 12.5, fontWeight: 700, color: "#5C6B5F", textAlign: "center", padding: "0 20px" }}>{caption}</div>
        <div style={{ fontSize: 11, color: "#8B9A8E" }}>{lockLabel}</div>
      </div>
    );
  }
  if (videoId) {
    return (
      <div style={{ borderRadius: 16, overflow: "hidden", aspectRatio: "16/9", marginBottom: 16 }}>
        <iframe
          width="100%" height="100%" style={{ display: "block", border: "none" }}
          src={`https://www.youtube-nocookie.com/embed/${videoId}`}
          title={caption} allowFullScreen
        />
      </div>
    );
  }
  return (
    <div className="video-card" style={{ position: "relative", borderRadius: 16, overflow: "hidden", aspectRatio: "16/9", background: "linear-gradient(135deg, #26332B, #3A4A3E)", marginBottom: 16, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ position: "absolute", top: 14, left: 14, display: "flex", alignItems: "center", gap: 8 }}>
        <div style={{ width: 26, height: 26, borderRadius: "50%", overflow: "hidden", flexShrink: 0 }}>
          <img src={NATHALIA_PHOTO} alt="Nathália Lucca" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
        </div>
        <span style={{ color: "#F3F1E9", fontSize: 11.5, fontWeight: 600 }}>Nathália Lucca</span>
      </div>
      <div style={{ width: 54, height: 54, borderRadius: "50%", background: "rgba(243,241,233,0.92)", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <Play size={22} color="#26332B" fill="#26332B" style={{ marginLeft: 3 }} />
      </div>
      <div style={{ position: "absolute", bottom: 12, left: 14, right: 14, color: "#F3F1E9", fontSize: 11.5, lineHeight: 1.4 }}>{caption}</div>
    </div>
  );
}

function Progress({ current }) {
  if (!GATED.includes(current)) return null;
  const idx = GATED.indexOf(current);
  return (
    <div style={{ display: "flex", gap: 5, marginBottom: 20 }}>
      {GATED.map((_, i) => (
        <div key={i} style={{ flex: 1, height: 4, borderRadius: 2, background: i <= idx ? "#5B7A63" : "#E4DECB" }} />
      ))}
    </div>
  );
}

function Shell({ children, showBack, step, onBack }) {
  return (
    <div style={WRAP_STYLE}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,600;9..144,700&family=Inter:wght@400;500;600;700&family=IBM+Plex+Mono:wght@500;600&display=swap');
        .sprout-serif { font-family: 'Fraunces', serif; }
        .sprout-mono { font-family: 'IBM Plex Mono', monospace; }
        .btn-primary { transition: transform 0.15s ease, box-shadow 0.15s ease; }
        .btn-primary:hover { transform: translateY(-1px); box-shadow: 0 8px 20px rgba(91,122,99,0.35); }
        .blur-lock { filter: blur(6px); pointer-events: none; user-select: none; }
        .chip { transition: all 0.15s ease; cursor: pointer; }
        .region-card { transition: all 0.15s ease; cursor: pointer; }
        .region-card:hover { transform: translateY(-2px); border-color: #5B7A63 !important; }
        .video-card { transition: transform 0.15s ease; cursor: pointer; }
        .video-card:hover { transform: scale(1.01); }
        input:focus, select:focus { outline: none; border-color: #5B7A63 !important; }
      `}</style>
      <div style={{ maxWidth: 460, margin: "0 auto", padding: "28px 20px 60px", minHeight: "100vh", display: "flex", flexDirection: "column" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 22 }}>
          {showBack && (
            <button onClick={onBack}
              style={{ background: "none", border: "none", cursor: "pointer", padding: 4, marginRight: -4 }}>
              <ChevronLeft size={20} color="#6B7A70" />
            </button>
          )}
          <div style={{ width: 34, height: 34, borderRadius: 9, background: "#5B7A63", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            <Sprout size={18} color="#F3F1E9" />
          </div>
          <div className="sprout-serif" style={{ fontSize: 18, fontWeight: 600 }}>Freedom Score</div>
        </div>
        <Progress current={step} />
        <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>{children}</div>
      </div>
    </div>
  );
}

export default function FunilDiagnostico() {
  const [step, setStep] = useState("regiao");
  const [country, setCountry] = useState(null); // "BR" | "US"
  const [lead, setLead] = useState({ nome: "", email: "", telefone: "", pais: "", estado: "" });
  const [sim, setSim] = useState({ renda: "", gasto: "" });
  const [extra, setExtra] = useState({ apps: [], mercado: "" });
  const [checked, setChecked] = useState({});
  const [paying, setPaying] = useState(false);

  const isBR = country === "BR";
  const symbol = isBR ? "R$" : "$";
  const price = isBR ? 47 : 15;
  const fmt = (n) => Math.round(n).toLocaleString(isBR ? "pt-BR" : "en-US");

  const checkedCount = ALL_SCORED_ITEMS.filter((i) => checked[i.id]).length;
  const score = Math.round((checkedCount / ALL_SCORED_ITEMS.length) * 100);
  const cutCount = NAO_ESSENCIAL_ITEMS.filter((i) => checked[i.id]).length;
  const scoreMsg = score < 40
    ? "Você está no início da organização financeira — e perceber isso já é o passo mais importante."
    : score < 70
    ? "Você já tem uma base sólida, mas ainda tem espaço real pra melhorar."
    : "Você já tem ótimos hábitos! Vamos refinar o que ainda falta.";
  const toggleCheck = (id) => setChecked((prev) => ({ ...prev, [id]: !prev[id] }));

  const renda = parseFloat(sim.renda) || 0;
  const gasto = parseFloat(sim.gasto) || 0;
  const guardaAtual = renda - gasto;
  const metaRecomendada = renda * 0.2;
  const potencial = Math.max(0, metaRecomendada - guardaAtual);
  const pieData = CATEGORY_SPLIT.map((c) => ({ ...c, value: Math.max(1, gasto * c.pct) }));

  const goTo = (s) => { setStep(s); window.scrollTo?.({ top: 0 }); };
  const goBack = () => goTo(STEP_ORDER[STEP_ORDER.indexOf(step) - 1]);
  const toggleApp = (app) => setExtra((prev) => ({
    ...prev,
    apps: prev.apps.includes(app) ? prev.apps.filter((a) => a !== app) : [...prev.apps, app],
  }));

  // ---------- REGIÃO / MOEDA ----------
  if (step === "regiao") {
    return (
      <Shell step={step}>
        <div style={{ textAlign: "center", marginTop: 40, marginBottom: 30 }}>
          <div className="sprout-serif" style={{ fontSize: 22, fontWeight: 600, marginBottom: 8 }}>Onde você mora?</div>
          <div style={{ fontSize: 13.5, color: "#5C6B5F" }}>Assim já mostramos tudo na moeda certa pra você</div>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <div className="region-card" onClick={() => { setCountry("US"); goTo("hero"); }}
            style={{ border: "1.5px solid #E4DECB", borderRadius: 16, padding: "18px 20px", display: "flex", alignItems: "center", gap: 14, background: "#FBF9F3" }}>
            <span style={{ fontSize: 26 }}>🇺🇸</span>
            <div>
              <div style={{ fontSize: 14.5, fontWeight: 700 }}>Estados Unidos</div>
              <div style={{ fontSize: 12, color: "#8B9A8E" }}>Valores em dólar (USD)</div>
            </div>
          </div>
          <div className="region-card" onClick={() => { setCountry("BR"); goTo("hero"); }}
            style={{ border: "1.5px solid #E4DECB", borderRadius: 16, padding: "18px 20px", display: "flex", alignItems: "center", gap: 14, background: "#FBF9F3" }}>
            <span style={{ fontSize: 26 }}>🇧🇷</span>
            <div>
              <div style={{ fontSize: 14.5, fontWeight: 700 }}>Brasil</div>
              <div style={{ fontSize: 12, color: "#8B9A8E" }}>Valores em real (BRL)</div>
            </div>
          </div>
        </div>
      </Shell>
    );
  }

  // ---------- HERO ----------
  if (step === "hero") {
    return (
      <Shell showBack step={step} onBack={goBack}>
        <div style={{ textAlign: "center", marginTop: 12 }}>
          <div style={{ display: "inline-flex", alignItems: "center", gap: 6, background: "#EFEADB", borderRadius: 999, padding: "6px 14px", marginBottom: 20 }}>
            <Sparkles size={13} color="#5B7A63" />
            <span style={{ fontSize: 11.5, fontWeight: 600, color: "#5B7A63" }}>Leva 2 minutos</span>
          </div>
          <div className="sprout-serif" style={{ fontSize: 27, fontWeight: 700, lineHeight: 1.22, marginBottom: 16 }}>
            Descubra quanto você poderia estar guardando todo mês
          </div>
        </div>

        <VideoCard caption="Nathália explica em 90 segundos o que você vai receber" videoId={VIDEO_LINKS.hero} />

        <div style={{ fontSize: 13.5, color: "#5C6B5F", lineHeight: 1.55, marginBottom: 24, textAlign: "center", padding: "0 4px" }}>
          Responda algumas perguntas rápidas e receba um diagnóstico real, feito pra sua renda e seus gastos — não uma média genérica.
        </div>

        <button className="btn-primary" onClick={() => goTo("cadastro")}
          style={{ width: "100%", background: "#5B7A63", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginBottom: 18 }}>
          Ver quanto eu poderia guardar <ArrowRight size={17} />
        </button>

        <div style={{ display: "flex", alignItems: "center", gap: 10, background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: "12px 14px" }}>
          <div style={{ width: 34, height: 34, borderRadius: "50%", overflow: "hidden", flexShrink: 0 }}>
            <img src={NATHALIA_PHOTO} alt="Nathália Lucca" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          </div>
          <div style={{ fontSize: 11.5, color: "#5C6B5F", lineHeight: 1.4 }}>
            Criado por <strong style={{ color: "#26332B" }}>Nathália Lucca</strong>, especialista em planejamento financeiro e aposentadoria
          </div>
        </div>
      </Shell>
    );
  }

  // ---------- CADASTRO ----------
  if (step === "cadastro") {
    const canContinue = lead.nome.trim() && lead.email.includes("@") && lead.telefone.trim().length >= 8 && lead.pais.trim() && lead.estado.trim();
    return (
      <Shell showBack step={step} onBack={goBack}>
        <div className="sprout-serif" style={{ fontSize: 20, fontWeight: 600, marginBottom: 6 }}>Vamos começar com você</div>
        <div style={{ fontSize: 13, color: "#5C6B5F", marginBottom: 22, lineHeight: 1.5 }}>Seus dados ficam só entre a gente — nada de spam.</div>

        <div style={{ display: "grid", gridTemplateColumns: "1fr", gap: 16, marginBottom: 4 }}>
          {[
            { icon: User, key: "nome", label: "Nome", placeholder: "Seu nome" },
            { icon: Mail, key: "email", label: "E-mail", placeholder: "voce@email.com" },
            { icon: Phone, key: "telefone", label: "Telefone / WhatsApp", placeholder: "(00) 00000-0000" },
          ].map((f) => (
            <div key={f.key}>
              <label style={{ fontSize: 12.5, fontWeight: 600, color: "#4B5A50" }}>{f.label}</label>
              <div style={{ position: "relative", marginTop: 6 }}>
                <f.icon size={16} color="#8B9A8E" style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)" }} />
                <input value={lead[f.key]} onChange={(e) => setLead({ ...lead, [f.key]: e.target.value })} placeholder={f.placeholder}
                  style={{ width: "100%", border: "1.5px solid #D8D2BC", borderRadius: 12, padding: "13px 14px 13px 40px", fontSize: 14.5, background: "#FFFFFF", boxSizing: "border-box" }} />
              </div>
            </div>
          ))}

          <div style={{ display: "flex", gap: 10 }}>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12.5, fontWeight: 600, color: "#4B5A50" }}>País</label>
              <div style={{ position: "relative", marginTop: 6 }}>
                <MapPin size={16} color="#8B9A8E" style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)" }} />
                <input value={lead.pais} onChange={(e) => setLead({ ...lead, pais: e.target.value })} placeholder={isBR ? "Brasil" : "Estados Unidos"}
                  style={{ width: "100%", border: "1.5px solid #D8D2BC", borderRadius: 12, padding: "13px 14px 13px 40px", fontSize: 14.5, background: "#FFFFFF", boxSizing: "border-box" }} />
              </div>
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 12.5, fontWeight: 600, color: "#4B5A50" }}>Estado</label>
              <input value={lead.estado} onChange={(e) => setLead({ ...lead, estado: e.target.value })} placeholder={isBR ? "São Paulo" : "Florida"}
                style={{ width: "100%", border: "1.5px solid #D8D2BC", borderRadius: 12, padding: "13px 14px", fontSize: 14.5, background: "#FFFFFF", boxSizing: "border-box", marginTop: 6 }} />
            </div>
          </div>
        </div>

        <div style={{ flex: 1, minHeight: 20 }} />
        <div style={{ fontSize: 10.5, color: "#8B9A8E", textAlign: "center", marginTop: 14, lineHeight: 1.4 }}>
          Ao continuar, você concorda em receber contato da Nathália por e-mail ou WhatsApp sobre o seu diagnóstico.
        </div>
        <button className="btn-primary" disabled={!canContinue} onClick={() => goTo("financas")}
          style={{ width: "100%", background: canContinue ? "#5B7A63" : "#C9C4B0", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: canContinue ? "pointer" : "not-allowed", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginTop: 8 }}>
          Continuar <ArrowRight size={17} />
        </button>
      </Shell>
    );
  }

  // ---------- FINANÇAS ----------
  if (step === "financas") {
    return (
      <Shell showBack step={step} onBack={goBack}>
        <div className="sprout-serif" style={{ fontSize: 20, fontWeight: 600, marginBottom: 6 }}>Agora, seus números</div>
        <div style={{ fontSize: 13, color: "#5C6B5F", marginBottom: 22, lineHeight: 1.5 }}>Não precisa ser exato — um valor aproximado já é suficiente.</div>

        <label style={{ fontSize: 12.5, fontWeight: 600, color: "#4B5A50" }}>Quanto você recebe por mês? (líquido)</label>
        <div style={{ position: "relative", margin: "8px 0 18px" }}>
          <span style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)", color: "#8B9A8E", fontSize: 15 }}>{symbol}</span>
          <input type="number" value={sim.renda} onChange={(e) => setSim({ ...sim, renda: e.target.value })} placeholder={isBR ? "5.000" : "5,000"}
            style={{ width: "100%", border: "1.5px solid #D8D2BC", borderRadius: 12, padding: "13px 14px 13px 44px", fontSize: 16, background: "#FFFFFF", boxSizing: "border-box" }} />
        </div>

        <label style={{ fontSize: 12.5, fontWeight: 600, color: "#4B5A50" }}>Quanto você gasta, no total, por mês?</label>
        <div style={{ position: "relative", margin: "8px 0 26px" }}>
          <span style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)", color: "#8B9A8E", fontSize: 15 }}>{symbol}</span>
          <input type="number" value={sim.gasto} onChange={(e) => setSim({ ...sim, gasto: e.target.value })} placeholder={isBR ? "4.400" : "4,400"}
            style={{ width: "100%", border: "1.5px solid #D8D2BC", borderRadius: 12, padding: "13px 14px 13px 44px", fontSize: 16, background: "#FFFFFF", boxSizing: "border-box" }} />
        </div>

        <div style={{ flex: 1 }} />
        <button className="btn-primary" disabled={!renda || !gasto} onClick={() => goTo("detalhes")}
          style={{ width: "100%", background: renda && gasto ? "#5B7A63" : "#C9C4B0", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: renda && gasto ? "pointer" : "not-allowed", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          Continuar <ArrowRight size={17} />
        </button>
      </Shell>
    );
  }

  // ---------- DETALHES (apps + mercado) ----------
  if (step === "detalhes") {
    return (
      <Shell showBack step={step} onBack={goBack}>
        <div className="sprout-serif" style={{ fontSize: 20, fontWeight: 600, marginBottom: 6 }}>Só mais alguns detalhes</div>
        <div style={{ fontSize: 13, color: "#5C6B5F", marginBottom: 20, lineHeight: 1.5 }}>Isso ajuda a deixar seu diagnóstico bem mais preciso.</div>

        <label style={{ fontSize: 12.5, fontWeight: 600, color: "#4B5A50", display: "block", marginBottom: 8 }}>Quais apps / assinaturas você paga?</label>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 22 }}>
          {APP_OPTIONS.map((app) => {
            const active = extra.apps.includes(app);
            return (
              <div key={app} className="chip" onClick={() => toggleApp(app)}
                style={{ padding: "8px 14px", borderRadius: 999, border: active ? "1.5px solid #5B7A63" : "1.5px solid #D8D2BC", background: active ? "#5B7A63" : "#FFFFFF", color: active ? "#F3F1E9" : "#4B5A50", fontSize: 12.5, fontWeight: 600 }}>
                {app}
              </div>
            );
          })}
        </div>

        <label style={{ fontSize: 12.5, fontWeight: 600, color: "#4B5A50" }}>Onde você costuma fazer compras no mercado?</label>
        <div style={{ position: "relative", margin: "8px 0 26px" }}>
          <ShoppingCart size={16} color="#8B9A8E" style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)" }} />
          <input value={extra.mercado} onChange={(e) => setExtra({ ...extra, mercado: e.target.value })} placeholder={isBR ? "ex: Pão de Açúcar, Carrefour..." : "ex: Walmart, Costco, Publix..."}
            style={{ width: "100%", border: "1.5px solid #D8D2BC", borderRadius: 12, padding: "13px 14px 13px 40px", fontSize: 14.5, background: "#FFFFFF", boxSizing: "border-box" }} />
        </div>

        <div style={{ flex: 1 }} />
        <button className="btn-primary" onClick={() => goTo("prioridades")}
          style={{ width: "100%", background: "#5B7A63", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          Ver minha ordem de prioridades <ArrowRight size={17} />
        </button>
      </Shell>
    );
  }

  // ---------- CHECKLIST DE HÁBITOS FINANCEIROS ----------
  if (step === "prioridades") {
    const CheckRow = ({ item }) => {
      const active = !!checked[item.id];
      return (
        <div className="chip" onClick={() => toggleCheck(item.id)}
          style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 14px", borderRadius: 12, border: active ? "1.5px solid #5B7A63" : "1.5px solid #E4DECB", background: active ? "#EAF3DE" : "#FBF9F3", marginBottom: 8 }}>
          <div style={{ width: 20, height: 20, borderRadius: 6, border: active ? "none" : "1.5px solid #C9C4B0", background: active ? "#5B7A63" : "transparent", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            {active && <Check size={13} color="#F3F1E9" />}
          </div>
          <span style={{ fontSize: 13, color: "#26332B", lineHeight: 1.35 }}>{item.label}</span>
        </div>
      );
    };

    const CutRow = ({ item }) => {
      const active = !!checked[item.id];
      return (
        <div className="chip" onClick={() => toggleCheck(item.id)}
          style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 14px", borderRadius: 12, border: active ? "1.5px solid #B5657A" : "1.5px solid #E4DECB", background: active ? "#FBEAF0" : "#FBF9F3", marginBottom: 8 }}>
          <div style={{ width: 20, height: 20, borderRadius: 6, border: active ? "none" : "1.5px solid #C9C4B0", background: active ? "#B5657A" : "transparent", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            {active && <Check size={13} color="#F3F1E9" />}
          </div>
          <span style={{ fontSize: 13, color: "#26332B", lineHeight: 1.35 }}>{item.label}</span>
        </div>
      );
    };

    return (
      <Shell showBack step={step} onBack={goBack}>
        <div className="sprout-serif" style={{ fontSize: 20, fontWeight: 600, marginBottom: 4 }}>Marque o que já faz parte da sua vida</div>
        <div style={{ fontSize: 13, color: "#5C6B5F", marginBottom: 4, lineHeight: 1.5 }}>
          Quanto mais você marcar, mais preciso fica o seu diagnóstico.
        </div>

        <div style={{ position: "sticky", top: 0, zIndex: 5, background: "#F3F1E9", paddingTop: 6, paddingBottom: 10, marginBottom: 6 }}>
          <div style={{ background: "#26332B", borderRadius: 14, padding: "12px 16px" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
              <span style={{ color: "#B9C4B4", fontSize: 11, fontWeight: 600 }}>SEU PONTO DE PARTIDA</span>
              <span className="sprout-mono" style={{ color: "#8FB396", fontSize: 15, fontWeight: 700 }}>{score}%</span>
            </div>
            <div style={{ height: 7, background: "#1D2721", borderRadius: 4, overflow: "hidden" }}>
              <div style={{ height: "100%", width: `${score}%`, background: "linear-gradient(90deg, #8FB396, #5B7A63)", transition: "width 0.3s ease" }} />
            </div>
          </div>
        </div>

        <div style={{ fontSize: 12.5, fontWeight: 700, color: "#5B7A63", margin: "10px 0 4px", textTransform: "uppercase", letterSpacing: 0.4 }}>Essencial</div>
        <div style={{ fontSize: 11.5, color: "#8B9A8E", marginBottom: 10 }}>O que sustenta sua base financeira</div>
        {ESSENCIAL_ITEMS.map((item) => <CheckRow key={item.id} item={item} />)}

        <div style={{ fontSize: 12.5, fontWeight: 700, color: "#C98A4B", margin: "14px 0 4px", textTransform: "uppercase", letterSpacing: 0.4 }}>Necessário flexível</div>
        <div style={{ fontSize: 11.5, color: "#8B9A8E", marginBottom: 10 }}>Gastos que dá pra reduzir — se você tiver controle sobre eles</div>
        {FLEXIVEL_ITEMS.map((item) => <CheckRow key={item.id} item={item} />)}

        <div style={{ fontSize: 12.5, fontWeight: 700, color: "#B5657A", margin: "14px 0 4px", textTransform: "uppercase", letterSpacing: 0.4 }}>Não essencial — pode cortar</div>
        <div style={{ fontSize: 11.5, color: "#8B9A8E", marginBottom: 10 }}>Marque o que soa familiar — é aqui que mora a economia mais rápida</div>
        {NAO_ESSENCIAL_ITEMS.map((item) => <CutRow key={item.id} item={item} />)}

        <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: 14, margin: "14px 0 4px", textAlign: "center" }}>
          <div style={{ fontSize: 12.5, color: "#4B5A50", lineHeight: 1.5, marginBottom: cutCount > 0 ? 6 : 0 }}>{scoreMsg}</div>
          {cutCount > 0 && (
            <div style={{ fontSize: 12, color: "#993556", fontWeight: 600 }}>
              Você marcou {cutCount} {cutCount === 1 ? "hábito" : "hábitos"} que dá pra revisar
            </div>
          )}
        </div>

        <div style={{ flex: 1 }} />
        <button className="btn-primary" onClick={() => goTo("parcial")}
          style={{ width: "100%", background: "#5B7A63", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginTop: 16 }}>
          Ver meu diagnóstico <ArrowRight size={17} />
        </button>
      </Shell>
    );
  }

  // ---------- DIAGNÓSTICO PARCIAL ----------
  if (step === "parcial") {
    return (
      <Shell showBack step={step} onBack={goBack}>
        <div className="sprout-serif" style={{ fontSize: 20, fontWeight: 600, marginBottom: 4 }}>Seu diagnóstico rápido, {lead.nome.split(" ")[0] || ""}</div>
        <div style={{ fontSize: 13, color: "#5C6B5F", marginBottom: 14 }}>Baseado no que você informou e marcou</div>

        <div style={{ background: "#26332B", borderRadius: 14, padding: "12px 16px", marginBottom: 14, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <span style={{ color: "#B9C4B4", fontSize: 12 }}>
            Seu ponto de partida{cutCount > 0 ? ` · ${cutCount} ${cutCount === 1 ? "hábito" : "hábitos"} pra revisar` : ""}
          </span>
          <span className="sprout-mono" style={{ color: "#8FB396", fontSize: 16, fontWeight: 700 }}>{score}%</span>
        </div>

        <div style={{ display: "flex", gap: 10, marginBottom: 14 }}>
          <div style={{ flex: 1, background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: 14 }}>
            <div style={{ fontSize: 11, color: "#8B9A8E", fontWeight: 600 }}>VOCÊ JÁ GUARDA</div>
            <div className="sprout-mono" style={{ fontSize: 19, fontWeight: 700, marginTop: 4 }}>{symbol} {fmt(Math.max(0, guardaAtual))}</div>
          </div>
          <div style={{ flex: 1, background: "#26332B", borderRadius: 14, padding: 14 }}>
            <div style={{ fontSize: 11, color: "#8FB396", fontWeight: 600 }}>PODERIA GUARDAR</div>
            <div className="sprout-mono" style={{ fontSize: 19, fontWeight: 700, marginTop: 4, color: "#F3F1E9" }}>+{symbol} {fmt(potencial)}</div>
          </div>
        </div>

        <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: 16, marginBottom: 4, position: "relative" }}>
          <div className="blur-lock">
            <ResponsiveContainer width="100%" height={160}>
              <PieChart>
                <Pie data={pieData} dataKey="value" nameKey="name" innerRadius={40} outerRadius={65} paddingAngle={2}>
                  {pieData.map((d) => <Cell key={d.name} fill={d.color} />)}
                </Pie>
              </PieChart>
            </ResponsiveContainer>
            <div style={{ display: "flex", justifyContent: "space-around", fontSize: 11, color: "#4B5A50" }}>
              {pieData.slice(0, 3).map((d) => <span key={d.name}>{d.name}</span>)}
            </div>
          </div>
          <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6 }}>
            <div style={{ background: "#26332B", borderRadius: "50%", width: 40, height: 40, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <Lock size={17} color="#F3F1E9" />
            </div>
            <div style={{ fontSize: 12.5, fontWeight: 700, color: "#26332B", textAlign: "center" }}>Plano categoria por categoria bloqueado</div>
          </div>
        </div>

        <div style={{ fontSize: 13, color: "#4B5A50", lineHeight: 1.5, marginBottom: 20, textAlign: "center", padding: "0 4px", fontWeight: 600 }}>
          Receba aqui um diagnóstico completo pra você conseguir guardar mais, e um plano prático pra controlar seus gastos.
        </div>

        <div style={{ flex: 1 }} />
        <button className="btn-primary" onClick={() => goTo("pagamento")}
          style={{ width: "100%", background: "#5B7A63", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          Quero meu diagnóstico completo <ArrowRight size={17} />
        </button>
      </Shell>
    );
  }

  // ---------- PAGAMENTO ----------
  if (step === "pagamento") {
    return (
      <Shell showBack step={step} onBack={goBack}>
        <div style={{ textAlign: "center", marginBottom: 16 }}>
          <div className="sprout-serif" style={{ fontSize: 20, fontWeight: 600, marginBottom: 6 }}>Seu diagnóstico está pronto</div>
          <div style={{ fontSize: 13, color: "#5C6B5F" }}>Falta só um passo pra desbloquear</div>
        </div>

        <VideoCard caption="Como funciona o acompanhamento depois do diagnóstico" videoId={VIDEO_LINKS.pagamento} />

        <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: "12px 16px", marginBottom: 14, textAlign: "center" }}>
          <span style={{ fontSize: 13, color: "#4B5A50" }}>Você já viu que poderia guardar </span>
          <span className="sprout-mono" style={{ fontSize: 14, fontWeight: 700, color: "#3B6D11" }}>+{symbol} {fmt(potencial)}/mês</span>
          <span style={{ fontSize: 13, color: "#4B5A50" }}> — falta só o plano pra chegar lá.</span>
        </div>

        <div style={{ background: "#26332B", borderRadius: 18, padding: 22, marginBottom: 16, textAlign: "center" }}>
          <div style={{ color: "#8FB396", fontSize: 11, fontWeight: 600, letterSpacing: 0.4, marginBottom: 4 }}>DIAGNÓSTICO COMPLETO</div>
          <div className="sprout-mono" style={{ color: "#F3F1E9", fontSize: 34, fontWeight: 700 }}>{symbol}{price}</div>
          <div style={{ color: "#B9C4B4", fontSize: 11.5, marginTop: 2 }}>pagamento único · menos que um jantar fora</div>
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 14 }}>
          {[
            "Saiba exatamente em quais categorias cortar — sem adivinhação",
            "Um número exato pra guardar todo mês, calculado pra sua renda real",
            "Descubra quais assinaturas valem a pena manter e quanto isso libera por ano",
            "Vídeos exclusivos da Nathália sobre sua relação emocional com o dinheiro",
          ].map((item) => (
            <div key={item} style={{ display: "flex", alignItems: "flex-start", gap: 8 }}>
              <div style={{ background: "#EAF3DE", borderRadius: "50%", width: 20, height: 20, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, marginTop: 1 }}>
                <Check size={12} color="#3B6D11" />
              </div>
              <span style={{ fontSize: 13.5, color: "#26332B" }}>{item}</span>
            </div>
          ))}
        </div>

        {!isBR && (
          <div style={{ background: "#FDF6E8", border: "1.5px dashed #E0B84D", borderRadius: 14, padding: 16, marginBottom: 14 }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: "#8A6414", marginBottom: 4 }}>🎁 Bônus, sem custo adicional</div>
            <div style={{ fontSize: 13, color: "#5C4A1E", lineHeight: 1.5, marginBottom: 8 }}>
              Por morar nos Estados Unidos, você também ganha uma consultoria gratuita com a Nathália pra falar sobre aposentadoria e proteção financeira.
            </div>
            <div style={{ fontSize: 10.5, color: "#8B7A4F", lineHeight: 1.4, fontStyle: "italic" }}>
              Consultoria conduzida por Nathália Lucca, profissional licenciada em seguros e estratégias financeiras nos Estados Unidos. Produtos de estratégias financeiras e proteção podem ser apresentados durante a conversa. Não é aconselhamento de investimento — é orientação sobre produtos financeiros conservadores, como seguros e planejamento de aposentadoria. Não há obrigação de compra.
            </div>
          </div>
        )}

        <div style={{ border: "1px dashed #D8D2BC", borderRadius: 14, padding: 14, marginBottom: 18, textAlign: "center" }}>
          <div style={{ fontSize: 11.5, color: "#8B9A8E", fontStyle: "italic" }}>
            [ espaço reservado pra um depoimento real de cliente — troque assim que tiver o primeiro ]
          </div>
        </div>

        <div style={{ flex: 1 }} />
        <button className="btn-primary" disabled={paying} onClick={() => { setPaying(true); setTimeout(() => { setPaying(false); goTo("completo"); }, 1100); }}
          style={{ width: "100%", background: "#5B7A63", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginBottom: 10 }}>
          <CreditCard size={17} /> {paying ? "Processando…" : "Pagar e desbloquear"}
        </button>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 5, fontSize: 11, color: "#8B9A8E" }}>
          <ShieldCheck size={12} /> pagamento seguro
        </div>
      </Shell>
    );
  }

  // ---------- DIAGNÓSTICO COMPLETO ----------
  if (step === "completo") {
    return (
      <Shell step={step}>
        <div style={{ textAlign: "center", marginBottom: 20 }}>
          <div style={{ display: "inline-flex", alignItems: "center", justifyContent: "center", width: 48, height: 48, borderRadius: "50%", background: "#EAF3DE", marginBottom: 12 }}>
            <PartyPopper size={22} color="#3B6D11" />
          </div>
          <div className="sprout-serif" style={{ fontSize: 21, fontWeight: 600 }}>Diagnóstico desbloqueado, {lead.nome.split(" ")[0] || ""}!</div>
        </div>

        <div style={{ display: "flex", gap: 10, marginBottom: 16 }}>
          <div style={{ flex: 1, background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: 14 }}>
            <div style={{ fontSize: 11, color: "#8B9A8E", fontWeight: 600 }}>RENDA</div>
            <div className="sprout-mono" style={{ fontSize: 17, fontWeight: 700, marginTop: 4 }}>{symbol} {fmt(renda)}</div>
          </div>
          <div style={{ flex: 1, background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: 14 }}>
            <div style={{ fontSize: 11, color: "#8B9A8E", fontWeight: 600 }}>META DE POUPANÇA</div>
            <div className="sprout-mono" style={{ fontSize: 17, fontWeight: 700, marginTop: 4 }}>{symbol} {fmt(metaRecomendada)}</div>
          </div>
        </div>

        <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 16, padding: "14px 8px", marginBottom: 14 }}>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie data={pieData} dataKey="value" nameKey="name" innerRadius={50} outerRadius={78} paddingAngle={2}>
                {pieData.map((d) => <Cell key={d.name} fill={d.color} />)}
              </Pie>
            </PieChart>
          </ResponsiveContainer>
          <div style={{ display: "flex", flexWrap: "wrap", gap: "6px 14px", justifyContent: "center" }}>
            {pieData.map((d) => (
              <div key={d.name} style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 11.5, color: "#4B5A50" }}>
                <div style={{ width: 8, height: 8, borderRadius: "50%", background: d.color }} />
                {d.name} · {symbol} {fmt(d.value)}
              </div>
            ))}
          </div>
        </div>

        {(extra.apps.length > 0 || extra.mercado) && (
          <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: 14, marginBottom: 14 }}>
            {extra.apps.length > 0 && (
              <div style={{ fontSize: 12.5, color: "#4B5A50", marginBottom: extra.mercado ? 6 : 0 }}>
                <strong style={{ color: "#26332B" }}>Assinaturas informadas:</strong> {extra.apps.join(", ")}
              </div>
            )}
            {extra.mercado && (
              <div style={{ fontSize: 12.5, color: "#4B5A50" }}>
                <strong style={{ color: "#26332B" }}>Mercado:</strong> {extra.mercado}
              </div>
            )}
          </div>
        )}

        {cutCount > 0 && (
          <div style={{ marginBottom: 14 }}>
            <div style={{ fontSize: 13.5, fontWeight: 700, color: "#26332B", marginBottom: 8 }}>Seus hábitos pra revisar primeiro</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {NAO_ESSENCIAL_ITEMS.filter((i) => checked[i.id]).map((i) => (
                <div key={i.id} style={{ display: "flex", alignItems: "center", gap: 8, background: "#FBEAF0", border: "1px solid #F0C6D3", borderRadius: 10, padding: "9px 12px" }}>
                  <div style={{ width: 6, height: 6, borderRadius: "50%", background: "#B5657A", flexShrink: 0 }} />
                  <span style={{ fontSize: 12.5, color: "#4B1528" }}>{i.label}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div style={{ background: "#EFEADB", border: "1px dashed #C7BE9E", borderRadius: 14, padding: 16, marginBottom: 18 }}>
          <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 4 }}>Seus próximos 3 meses</div>
          <div style={{ fontSize: 12.5, color: "#5C6B5F", lineHeight: 1.5 }}>
            Corte gradual nos hábitos marcados acima, automatize {symbol} {fmt(metaRecomendada / 4)}/semana pra poupança, e reveja assinaturas todo trimestre.
          </div>
        </div>

        <div style={{ background: "#FBF9F3", border: "1px solid #E4DECB", borderRadius: 14, padding: 14, marginBottom: 18, display: "flex", gap: 10, alignItems: "flex-start" }}>
          <div style={{ fontSize: 18 }}>📩</div>
          <div>
            <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 2 }}>Vídeos com a Nathália, ao longo de 3 semanas</div>
            <div style={{ fontSize: 12, color: "#5C6B5F", lineHeight: 1.4 }}>
              Você vai receber por e-mail o acesso aos vídeos sobre a relação emocional com o dinheiro — um novo a cada 7 dias, pra dar tempo de você realmente aplicar antes do próximo.
            </div>
          </div>
        </div>

        {!isBR ? (
          <div style={{ background: "#FDF6E8", border: "1.5px solid #E0B84D", borderRadius: 14, padding: 16, marginBottom: 18 }}>
            <div style={{ fontSize: 13.5, fontWeight: 700, color: "#8A6414", marginBottom: 4 }}>🎁 Sua consultoria gratuita está liberada</div>
            <div style={{ fontSize: 12.5, color: "#5C4A1E", lineHeight: 1.45, marginBottom: 10 }}>
              Sem custo adicional — converse com a Nathália sobre aposentadoria e proteção financeira.
            </div>
            <button className="btn-primary" style={{ width: "100%", background: "#8A6414", color: "#FFFDF6", border: "none", borderRadius: 12, padding: "13px", fontSize: 14, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginBottom: 8 }}>
              <Calendar size={16} /> Agendar minha consultoria gratuita
            </button>
            <div style={{ fontSize: 10, color: "#8B7A4F", lineHeight: 1.4, fontStyle: "italic" }}>
              Conduzida por Nathália Lucca, profissional licenciada em seguros e estratégias financeiras nos Estados Unidos. Produtos de estratégias financeiras e proteção podem ser apresentados durante a conversa. Não é aconselhamento de investimento — é orientação sobre produtos financeiros conservadores, como seguros e planejamento de aposentadoria. Não há obrigação de compra.
            </div>
          </div>
        ) : (
          <div style={{ border: "1px dashed #D8D2BC", borderRadius: 14, padding: 16, marginBottom: 18, textAlign: "center" }}>
            <div style={{ fontSize: 12.5, fontWeight: 700, color: "#4B5A50", marginBottom: 2 }}>🔒 Em breve</div>
            <div style={{ fontSize: 12, color: "#8B9A8E", lineHeight: 1.4 }}>Mentoria individual com a Nathália, pra quem quiser ir além do plano</div>
          </div>
        )}

        <div style={{ flex: 1 }} />
        <button className="btn-primary" onClick={() => goTo("app")}
          style={{ width: "100%", background: "#5B7A63", color: "#F3F1E9", border: "none", borderRadius: 14, padding: "16px", fontSize: 15, fontWeight: 700, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          <Sprout size={17} /> Continuar no app e acompanhar meus gastos
        </button>
      </Shell>
    );
  }

  // ---------- APP COMPLETO (destino real do botão acima) ----------
  if (step === "app") {
    return (
      <Dashboard
        initialRenda={renda}
        initialGasto={gasto}
        initialApps={extra.apps}
        habitosParaRevisar={NAO_ESSENCIAL_ITEMS.filter((i) => checked[i.id]).map((i) => i.label)}
        symbol={symbol}
        isBR={isBR}
      />
    );
  }

  return null;
}
